with open('/work/src/be_strlib.c', 'r') as f:
    content = f.read()
    # Find the switch statement
    import re
    match = re.search(r'switch \(\*p\) \{(.*?)default:', content, re.DOTALL)
    if match:
        switch_body = match.group(1)
        if "'%'" in switch_body:
            print("Found case '%':")
            lines = switch_body.split('\n')
            for i, line in enumerate(lines):
                if "'%'" in line:
                    print(f"Line {i}: {line}")
                    for j in range(max(0, i-2), min(len(lines), i+5)):
                        print(f"  {j}: {lines[j]}")
        else:
            print("No case '%' found in switch statement")
